#include <bits/stdc++.h>
using namespace std;
using ll=long long;
using ld=long double;
using P=pair<ll,ll>;
using V=vector<ll>;
#define rep(i,n) for(int i=0;i<n;i++)
#define REP(i,n) for(int i=1;i<=n;i++)

vector<string> a(9);
vector<int> dx={-1,0,1,0},dy={0,1,0,-1};
int px=8,py=4;
int mx=0,my=4;

bool partner(){
    int task;
    cin >> task;
    if(task==0){
        int d;
        cin >> d;
        px+=dx[d];
        py+=dy[d];
        a[px][py]='.';
    }
    if(task==1||task==2){
        int x,y;
        cin >> x >> y;
    }
    if(task==3) return true;
    return false;

}

int dis(int ax,int ay,int bx,int by){
    return abs(ax-bx)+abs(ay-by);
}

int main(){
    int before=2;
    string firsec;
    cin >> firsec;
    rep(i,9) cin >> a[i];
    if(firsec=="Second"){
        if(partner()) return 0;
        before=0;
    }
    else swap(px,mx);


    while(true){
        ll u=0,d=0,l=0,r=0;
        rep(i,9) rep(j,9){
            if(dis(i,j,mx,my)<dis(i,j,px,py)&&a[i][j]=='#'){
                if(i<=mx&&abs(j-my)<=mx-i) u++;
                if(i>=mx&&abs(j-my)<=i-mx) d++;
                if(j<=my&&abs(i-mx)<=my-j) l++;
                if(j>=my&&abs(i-mx)<=j-my) r++;
            }
        }

        vector<ll> v={1,1,1,1};
        rep(l,4){
            int nx=mx+dx[l],ny=my+dy[l];
            if(0<=nx&&nx<9&&0<=ny&&ny<9){
                if(a[nx][ny]=='#') v[l]=1e9;
            }
        }
        v[before]=-1e9;

        u*=v[0];
        r*=v[1];
        d*=v[2];
        l*=v[3];

        if(u>=r&&u>=d&&u>=l&&mx>0){
            cout << "0 0" << endl;
            mx--;
            before=0;
        }
        else if(r>=u&&r>=d&&r>=l&&my<8){
            cout << "0 1" << endl;
            my++;
            before=1;
        }
        else if(d>=u&&d>=r&&d>=l&&mx<8){
            cout << "0 2" << endl;
            mx++;
            before=2;
        }
        else if(l>=u&&l>=r&&l>=d&&0<my){
            cout << "0 3" << endl;
            my--;
            before=3;
        }
        else if(0<mx){
            cout << "0 0" << endl;
            mx--;
            before=0;
        }
        else if(0<my){
            cout << "0 3" << endl;
            my--;
            before=3;
        }
        else if(mx<8){
            cout << "0 2" << endl;
            mx++;
            before=2;
        }
        else{
            cout << "0 1" << endl;
            my++;
            before=1;
        }

        a[mx][my]='.';

        if(partner()) return 0;

    }
}
